6669	
6670		for (i = 0; i < q->nr; i++) {
6671			p = q->queue[i];
6672			p->status = 0; /* undecided */
6673			if (DIFF_PAIR_UNMERGED(p))
6674				p->status = DIFF_STATUS_UNMERGED;
6675			else if (!DIFF_FILE_VALID(p->one))
6676				p->status = DIFF_STATUS_ADDED;
6677			else if (!DIFF_FILE_VALID(p->two))
6678				p->status = DIFF_STATUS_DELETED;
6679			else if (DIFF_PAIR_TYPE_CHANGED(p))
6680				p->status = DIFF_STATUS_TYPE_CHANGED;
6681	
6682			/* from this point on, we are dealing with a pair
6683			 * whose both sides are valid and of the same type, i.e.
6684			 * either in-place edit or rename/copy edit.
6685			 */
6686			else if (DIFF_PAIR_RENAME(p)) {
6687				/*
6688				 * A rename might have re-connected a broken
6689				 * pair up, causing the pathnames to be the
6690				 * same again. If so, that's not a rename at
6691				 * all, just a modification..
6692				 *
6693				 * Otherwise, see if this source was used for
6694				 * multiple renames, in which case we decrement
6695				 * the count, and call it a copy.
6696				 */
6697				if (!strcmp(p->one->path, p->two->path))
6698					p->status = DIFF_STATUS_MODIFIED;
6699				else if (--p->one->rename_used > 0)
6700					p->status = DIFF_STATUS_COPIED;
6701				else
6702					p->status = DIFF_STATUS_RENAMED;
6703			}
6704			else if (!oideq(&p->one->oid, &p->two->oid) ||
6705				 p->one->mode != p->two->mode ||
6706				 p->one->dirty_submodule ||
6707				 p->two->dirty_submodule ||
6708				 is_null_oid(&p->one->oid))
6709				p->status = DIFF_STATUS_MODIFIED;
6710			else {
6711				/* This is a "no-change" entry and should not
6712				 * happen anymore, but prepare for broken callers.
6713				 */
6714				error("feeding unmodified %s to diffcore",
6715				      p->one->path);
6716				p->status = DIFF_STATUS_UNKNOWN;
6717			}
6718		}
6719		diff_debug_queue("resolve-rename-copy done", q);
